  const auth = req.headers['authorization'] || '';
  const token = auth.replace(/^Bearer\s+/, '');
  if (!token || token !== process.env.API_TOKEN) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

app.get('/users', requireAuth, (req, res) => {
  res.json([...]);
});
```

